// File: Header.vue
<template>
  <header class="header">
    <div class="left">
        <router-link to="/home">
            <img src="../assets/htsocial.png" alt="Logo" class="logo" />
            <input type="text" placeholder="Search on HT Social..." class="search" />
        </router-link>
    </div>

    <div class="center">
      <router-link to="/home" class="nav-icon" active-class="active">
        <img src="../assets/home.png" class="icon-img" />
      </router-link>
      <router-link to="/friend" class="nav-icon" active-class="active">
        <img src="../assets/friend.png" class="icon-img" />
      </router-link>
      <router-link to="/marketplace" class="nav-icon" active-class="active">
        <img src="../assets/marketplace.png" class="icon-img" />
      </router-link>
      <router-link to="/group" class="nav-icon" active-class="active">
        <img src="../assets/group.png" class="icon-img" />
      </router-link>
      <router-link to="/game" class="nav-icon" active-class="active">
        <img src="../assets/game.png" class="icon-img" />
      </router-link>
    </div>

    <div class="right">
      <div class="icon-circle">
        <img src="../assets/menu.png" class="icon-img" />
      </div>
      <div class="icon-circle">
        <img src="../assets/message.png" class="icon-img" />
      </div>
      <div class="icon-circle notification">
        <img src="../assets/notification.png" class="icon-img" />
        <span class="badge">1</span>
      </div>
      <div class="icon-circle">
        <img src="../assets/user.png" class="avatar-image" />
      </div>
    </div>
  </header>
</template>

<script>
export default {
  name: 'MainHeader'
}
</script>

<style scoped>
.header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: white;
  height: 56px;
  padding: 0 16px;
  border-bottom: 1px solid #ccc;
  position: sticky;
  top: 0;
  z-index: 10;
}
.left {
  display: flex;
  align-items: center;
}
.logo {
  height: 36px;
  margin-right: 12px;
}
.search {
  background: #f0f2f5;
  border: none;
  padding: 8px 12px;
  border-radius: 999px;
  font-size: 14px;
  width: 220px;
}
.center {
  flex: 2;
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 40px;
}
.nav-icon {
  width: 45px;
  height: 45px;
  display: flex;
  justify-content: center;
  align-items: center;
  border-radius: 10px;
  cursor: pointer;
  transition: background 0.2s ease;
}
.nav-icon:hover {
  background-color: #f0f2f5;
}
.nav-icon.active {
  border-bottom: 3px solid #1877f2;
  background-color: #f0f2f5;
}
.icon-img {
  width: 24px;
  height: 24px;
  object-fit: contain;
}
.right {
  display: flex;
  align-items: center;
  gap: 10px;
}
.icon-circle {
  background: #e4e6eb;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  display: flex;
  justify-content: center;
  align-items: center;
  cursor: pointer;
  position: relative;
}
.badge {
  position: absolute;
  top: -2px;
  right: -2px;
  background: red;
  color: white;
  font-size: 10px;
  border-radius: 999px;
  padding: 2px 5px;
}
.avatar-image {
  width: 28px;
  height: 28px;
  border-radius: 999px;
  object-fit: cover;
}
</style>
